const fail = (message) => [{
  json: {
    success: false,
    error: message,
  },
}];

const body = $input.first().json.body;

if (!body || typeof body !== 'object') {
  return fail('Invalid request body');
}

const required = [
  'lesson_id',
  'submission_id',
  'student_id',
  'worksheet',
  'answer_key',
  'student_answers',
  'total_marks',
];

const missing = required.filter((field) => {
  const value = body[field];
  if (value === null || value === undefined) return true;
  if (typeof value === 'string' && value.trim() === '') return true;
  return false;
});

if (missing.length > 0) {
  return fail('Missing fields: ' + missing.join(', '));
}

if (!body.worksheet || typeof body.worksheet !== 'object') {
  return fail('Invalid worksheet');
}

if (!body.answer_key || typeof body.answer_key !== 'object') {
  return fail('Invalid answer_key');
}

if (!body.student_answers || typeof body.student_answers !== 'object') {
  return fail('Invalid student_answers');
}

const totalMarks = Number(body.total_marks);

if (!Number.isFinite(totalMarks) || totalMarks <= 0) {
  return fail('Invalid total_marks');
}

return [{
  json: {
    success: true,
    lesson_id: String(body.lesson_id),
    submission_id: String(body.submission_id),
    student_id: String(body.student_id),
    grade: String(body.grade || ''),
    worksheet: body.worksheet,
    answer_key: body.answer_key,
    student_answers: body.student_answers,
    total_marks: totalMarks,
  },
}];

const fail = (message) => [{
  json: {
    success: false,
    error: message,
  },
}];

const input = $input.first().json;

const raw =
  input?.choices?.[0]?.message?.content ||
  input?.body?.choices?.[0]?.message?.content ||
  input?.data?.choices?.[0]?.message?.content ||
  '';

if (!raw || typeof raw !== 'string') {
  return fail('Empty grading response from AI');
}

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  return fail('AI returned invalid grading JSON');
}

if (!parsed || typeof parsed !== 'object') {
  return fail('AI grading response is not an object');
}

const score = Number(parsed.score);
const totalMarks = Number(parsed.total_marks);

if (!Number.isFinite(score)) {
  return fail('AI grading response missing valid score');
}

if (!Number.isFinite(totalMarks) || totalMarks <= 0) {
  return fail('AI grading response missing valid total_marks');
}

if (score < 0 || score > totalMarks) {
  return fail('AI grading score is outside valid range');
}

if (!parsed.grade || typeof parsed.grade !== 'string') {
  return fail('AI grading response missing grade');
}

if (!Array.isArray(parsed.breakdown)) {
  return fail('AI grading response missing breakdown');
}

const cleanBreakdown = parsed.breakdown.map((item, index) => {
  const maxMarks = Number(item.max_marks ?? 0);
  const marksAwarded = Number(item.marks_awarded ?? 0);

  return {
    q_number: item.q_number ?? index + 1,
    student_answer: String(item.student_answer ?? ''),
    correct_answer: String(item.correct_answer ?? ''),
    marks_awarded: Number.isFinite(marksAwarded) ? Math.max(0, marksAwarded) : 0,
    max_marks: Number.isFinite(maxMarks) ? Math.max(0, maxMarks) : 0,
    feedback: String(item.feedback ?? ''),
  };
});

return [
  {
    json: {
      success: true,
      submission_id: $('Build Grading Prompt').first().json.submission_id || '',
      score,
      total_marks: totalMarks,
      grade: parsed.grade.trim().substring(0, 20),
      overall_feedback: String(parsed.overall_feedback || '').substring(0, 2000),
      breakdown: cleanBreakdown,
    },
  },
];

